#!/bin/bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-03-24

# Validate that rule references in test-cases.json point to actual rule files
# Catches mismatches like "contract-pact" when actual file is "verification-contract.md"
#
# Exit codes:
#   0 - All rule references valid
#   1 - Missing rule files detected

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "$SCRIPT_DIR/.." && pwd)"
SKILLS_DIR="$PROJECT_ROOT/src/skills"

RED='\033[0;31m'
GREEN='\033[0;32m'
NC='\033[0m'

ERRORS=0

for test_file in "$SKILLS_DIR"/*/test-cases.json; do
  [[ ! -f "$test_file" ]] && continue
  skill_dir=$(dirname "$test_file")
  skill_name=$(basename "$skill_dir")
  rules_dir="$skill_dir/rules"

  # Extract rule values from testCases[].rule (skip null/empty)
  rules=$(node -e "
    const d = require('$test_file');
    const cases = d.testCases || d.test_cases || (Array.isArray(d) ? d : []);
    cases.forEach(c => {
      if (c.rule && c.rule !== 'null') console.log(c.rule);
    });
  " 2>/dev/null || true)

  for rule in $rules; do
    [[ -z "$rule" ]] && continue
    rule_file="$rules_dir/$rule.md"
    if [[ ! -f "$rule_file" ]]; then
      echo -e "  ${RED}✗${NC} $skill_name: rule '$rule' in test-cases.json but rules/$rule.md not found"
      ERRORS=$((ERRORS + 1))
    fi
  done
done

if [[ "$ERRORS" -gt 0 ]]; then
  echo ""
  echo -e "${RED}Rule reference validation FAILED: $ERRORS error(s)${NC}"
  exit 1
fi

echo -e "  ${GREEN}✓${NC} All test-cases.json rule references match actual files"
exit 0
